import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}
// DO NOT EDIT types below — auto-generated from the data contract





// ViewProps: define the props that ComponentView needs to render the UI.
// Include all data, callbacks, and computed values that the View will use.
interface ViewProps {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit: string;
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
  weatherIcon: string;
}

// Controller: business logic, wire hooks, data transformations
// Controller: business logic, wire hooks, data transformations
function ComponentController(props: Props): ViewProps {
  // Map weather condition to emoji icon
  const getWeatherIcon = (condition: string): string => {
    if (!condition || typeof condition !== 'string') return '🌤️';
    const normalizedCondition = condition.toLowerCase().trim();
    if (normalizedCondition.includes('sun')) return '☀️';
    if (normalizedCondition.includes('cloud')) return '☁️';
    if (normalizedCondition.includes('rain')) return '🌧️';
    if (normalizedCondition.includes('snow')) return '❄️';
    if (normalizedCondition.includes('storm') || normalizedCondition.includes('thunder')) return '⛈️';
    if (normalizedCondition.includes('wind')) return '💨';
    if (normalizedCondition.includes('fog') || normalizedCondition.includes('mist')) return '🌫️';
    return '🌤️';
  };

  const weatherIcon = getWeatherIcon(props.condition);


  const safeForecasts = props.forecast && Array.isArray(props.forecast) ? props.forecast : [];

  return {
    city: props.city,
    temperature: props.temperature,
    condition: props.condition,
    humidity: props.humidity,
    windSpeed: props.windSpeed,
    unit: props.unit,
    forecast: safeForecasts,
    weatherIcon,
  };
  }
// View: presentation and UI interactions (can have its own UI state like tabs, modals, hover)
// View: presentation and UI interactions (can have its own UI state like tabs, modals, hover)
function ComponentView(props: ViewProps) {
  // add any UI-only state here (tabs, accordions, scroll position, etc.)

  return (
    <Container maxWidth="lg" padding={24}>
      <Stack gap={24}>
        {/* HEADER */}
        <Stack gap={8}>
          <Heading level={2}>{props.city}</Heading>
           <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
            Current Weather
          </Text>
        </Stack>

        {/* MAIN WEATHER CARD */}
        <Card shadow="md" padding={32} radius="lg">
          <Stack gap={24}>
            {/* Temperature and Condition */}
            <Stack gap={16} align="center">
              <Box>
                 <Text size="4xl" weight="bold" color="var(--ggui-color-onSurface)" align="center">
                  {props.temperature}°{props.unit}
                </Text>
              </Box>
              <Stack gap={8} align="center">
                 <Text size="4xl" weight="bold" color="var(--ggui-color-primary-600)">{props.weatherIcon}</Text>
                 <Text size="lg" weight="semibold" color="var(--ggui-color-onSurface)">
                  {props.condition}
                </Text>
              </Stack>
            </Stack>

            {/* Humidity and Wind Speed */}
            <Divider orientation="horizontal" margin={0} />
            <Row gap={32} justify="center" align="start">
              <Stack gap={8} align="center">
                 <Icon name="droplets" size={24} color="var(--ggui-color-primary-600)" />
                <Stack gap={4} align="center">
                   <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                    Humidity
                  </Text>
                   <Text size="lg" weight="semibold" color="var(--ggui-color-onSurface)">
                    {props.humidity}%
                  </Text>
                </Stack>
              </Stack>

              <Stack gap={8} align="center">
                 <Icon name="wind" size={24} color="var(--ggui-color-primary-600)" />
                <Stack gap={4} align="center">
                   <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                    Wind Speed
                  </Text>
                   <Text size="lg" weight="semibold" color="var(--ggui-color-onSurface)">
                     {props.windSpeed} {props.unit === 'C' ? 'km/h' : 'mph'}
                  </Text>
                </Stack>
              </Stack>
            </Row>
          </Stack>
        </Card>

        {/* 5-DAY FORECAST */}
        <Stack gap={12}>
          <Heading level={4}>5-Day Forecast</Heading>
          <Row gap={12} wrap>
            {props.forecast.map((day, index) => (
              <Card
                key={index}
                padding={16}
                radius="md"
                shadow="sm"
                style={{ flex: '1 1 var(--ggui-spacing-12)' }}
              >
                <Stack gap={8} align="center">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)" weight="semibold">
                    {day.day || 'Day'}
                  </Text>
                  <Text size="2xl" color="var(--ggui-color-primary-600)">{day.icon || '🌤️'}</Text>
                  <Stack gap={4} align="center">
                    <Text variant="bodySmall" weight="semibold" color="var(--ggui-color-onSurface)">
                      {day.high || '--'}°
                    </Text>
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                      {day.low || '--'}°
                    </Text>
                  </Stack>
                </Stack>
              </Card>
            ))}
          </Row>
        </Stack>
      </Stack>
    </Container>
  );
}

// DO NOT EDIT render — it connects Controller to View
export default function render(props: Props) {
  const viewProps = ComponentController(props);
  return <ComponentView {...viewProps} />;
}

