// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}
// DO NOT EDIT types below — auto-generated from the data contract

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





// ViewProps: define the props that ComponentView needs to render the UI.
// Include all data, callbacks, and computed values that the View will use.
interface ViewProps {
  currentStep: number;
  name: string;
  email: string;
  satisfaction: number;
  features: string[];
  comments: string;
  onNameChange: (value: string) => void;
  onEmailChange: (value: string) => void;
  onSatisfactionChange: (value: number) => void;
  onFeatureToggle: (feature: string) => void;
  onCommentsChange: (value: string) => void;
  onNext: () => void;
  onBack: () => void;
  onSubmit: () => void;
  nameError: string;
  emailError: string;
  featureOptions: string[];
  satisfactionLabels: string[];
}

// Controller: business logic, wire hooks, data transformations
function ComponentController(props: Props): ViewProps {
  const [currentStep, setCurrentStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState<number>(0);
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');
  const [nameError, setNameError] = useState('');
  const [emailError, setEmailError] = useState('');

  const submit = useAction<ActionSubmitPayload>('submit');

  const validateEmail = (value: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(value);
  };

  const validateStep1 = (): boolean => {
    let isValid = true;
    if (!name.trim()) {
      setNameError('Name is required');
      isValid = false;
    } else {
      setNameError('');
    }
    if (!email.trim()) {
      setEmailError('Email is required');
      isValid = false;
    } else if (!validateEmail(email)) {
      setEmailError('Please enter a valid email address');
      isValid = false;
    } else {
      setEmailError('');
    }
    return isValid;
  };

  const handleNameChange = (value: string) => {
    setName(value);
    if (value.trim()) setNameError('');
  };

  const handleEmailChange = (value: string) => {
    setEmail(value);
    if (value.trim() && validateEmail(value)) setEmailError('');
  };

  const handleSatisfactionChange = (value: number) => {
    setSatisfaction(value);
  };

  const handleFeatureToggle = (feature: string) => {
    setFeatures((prev) =>
      prev.includes(feature)
        ? prev.filter((f) => f !== feature)
        : [...prev, feature]
    );
  };

  const handleCommentsChange = (value: string) => {
    if (value.length <= 500) {
      setComments(value);
    }
  };

  const handleNext = () => {
    if (currentStep === 1) {
      if (validateStep1()) {
        setCurrentStep(2);
      }
    } else if (currentStep < 4) {
      setCurrentStep(currentStep + 1);
    }
  };

  const handleBack = () => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  };

  const handleSubmit = () => {
    submit({
      name,
      email,
      satisfaction,
      features,
      comments,
    });
  };

  return {
    currentStep,
    name,
    email,
    satisfaction,
    features,
    comments,
    onNameChange: handleNameChange,
    onEmailChange: handleEmailChange,
    onSatisfactionChange: handleSatisfactionChange,
    onFeatureToggle: handleFeatureToggle,
    onCommentsChange: handleCommentsChange,
    onNext: handleNext,
    onBack: handleBack,
    onSubmit: handleSubmit,
    nameError,
    emailError,
    featureOptions: props.featureOptions,
    satisfactionLabels: props.satisfactionLabels,
  };
}

// View: presentation and UI interactions (can have its own UI state like tabs, modals, hover)
function ComponentView(props: ViewProps) {
  const isStep1Complete = !props.nameError && !props.emailError && props.name && props.email;
  const isStep2Complete = props.satisfaction > 0;
  const isStep3Complete = props.features.length > 0;
  const isStep4Complete = true; // comments are optional

  const stepProgressPercentage = ((props.currentStep - 1) / 3) * 100;

  const renderStep = () => {
    switch (props.currentStep) {
      case 1:
        return (
          <Stack gap={16}>
            <Input
              label="Name"
              value={props.name}
              onChange={props.onNameChange}
              placeholder="Enter your name"
              required
              error={props.nameError}
            />
            <Input
              label="Email"
              type="email"
              value={props.email}
              onChange={props.onEmailChange}
              placeholder="Enter your email"
              required
              error={props.emailError}
            />
          </Stack>
        );
      case 2:
        return (
          <Stack gap={12}>
            <Text variant="label">How satisfied are you with our service?</Text>
            <RadioGroup
              label="Satisfaction Rating"
              value={String(props.satisfaction)}
              onChange={(value: string) => props.onSatisfactionChange(parseInt(value, 10))}
              options={props.satisfactionLabels.map((label, index) => ({
                value: String(index + 1),
                label,
              }))}
              direction="vertical"
            />
          </Stack>
        );
      case 3:
        return (
          <Stack gap={12}>
            <Text variant="label">Which features interest you? (Select at least one)</Text>
            <Stack gap={8}>
              {props.featureOptions.map((feature) => (
                <Checkbox
                  key={feature}
                  label={feature}
                  checked={props.features.includes(feature)}
                  onChange={() => props.onFeatureToggle(feature)}
                />
              ))}
            </Stack>
          </Stack>
        );
      case 4:
        return (
          <Stack gap={12}>
            <TextArea
              label="Comments"
              value={props.comments}
              onChange={props.onCommentsChange}
              placeholder="Any additional feedback (optional)"
              rows={6}
              maxLength={500}
              showCount
            />
          </Stack>
        );
      case 5:
        // Final review step
        return (
          <Stack gap={16}>
            <Heading level={3}>Review Your Answers</Heading>
            <Stack gap={12} style={{ backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)', padding: 'var(--ggui-spacing-4, 16px)', borderRadius: 'var(--ggui-shape-radius-md, 8px)' }}>
              <Stack gap={8}>
                <Text variant="label">Name:</Text>
                <Text>{props.name}</Text>
              </Stack>
              <Stack gap={8}>
                <Text variant="label">Email:</Text>
                <Text>{props.email}</Text>
              </Stack>
              <Stack gap={8}>
                <Text variant="label">Satisfaction:</Text>
                <Text>{props.satisfactionLabels[props.satisfaction - 1]}</Text>
              </Stack>
              <Stack gap={8}>
                <Text variant="label">Features of Interest:</Text>
                <Text>{props.features.length > 0 ? props.features.join(', ') : 'None selected'}</Text>
              </Stack>
              <Stack gap={8}>
                <Text variant="label">Comments:</Text>
                <Text>{props.comments || '(No comments)'}</Text>
              </Stack>
            </Stack>
          </Stack>
        );
      default:
        return null;

  return (
    <Container maxWidth="lg" padding={24}>
      <Stack gap={24}>
        {/* PROGRESS HEADER */}
        <Stack gap={8}>
          <Stack direction="horizontal" align="center" justify="between">
            <Heading level={2}>Survey Form</Heading>
            <Badge variant="primary" size="sm">
              Step {props.currentStep} of 4
            </Badge>
          </Stack>
          <Progress
            value={stepProgressPercentage}
            max={100}
            variant="default"
            size="md"
            showLabel
          />
        </Stack>

        {/* STEP CONTENT */}
        <Card shadow="md" padding={24}>
          <Stack gap={20}>{renderStep()}</Stack>
        </Card>

        {/* NAVIGATION BUTTONS */}
        <Row gap={12} align="center" justify="end">
          <Button
            variant="ghost"
            onClick={props.onBack}
            disabled={props.currentStep === 1}
          >
            Back
          </Button>
          {props.currentStep < 5 ? (
            <Button
              variant="primary"
              onClick={props.onNext}
              disabled={
                (props.currentStep === 1 && !isStep1Complete) ||
                (props.currentStep === 2 && !isStep2Complete) ||
                (props.currentStep === 3 && !isStep3Complete)
              }
            >
              {props.currentStep === 4 ? 'Review' : 'Next'}
            </Button>
          ) : (
            <Button variant="primary" onClick={props.onSubmit}>
              Submit
            </Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}

// DO NOT EDIT render — it connects Controller to View
export default function render(props: Props) {
  const viewProps = ComponentController(props);
  return <ComponentView {...viewProps} />;
}

// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}
// DO NOT EDIT types below — auto-generated from the data contract

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




// ViewProps: define the props that ComponentView needs to render the UI.
// Include all data, callbacks, and computed values that the View will use.
interface ViewProps {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>;
  columns: Array<{ id?: string; name?: string }>;
  totalTasks: number;
  completedTasks: number;
  onMoveTask: (taskId: string, newColumn: string) => void;
  onEditTask: (taskId: string, title: string) => void;
  onCreateTask: (title: string, priority: 'low' | 'medium' | 'high', columnId: string) => void;
  taskChanges: StreamTaskChanged | null;
}

// Controller: business logic, wire hooks, data transformations
function ComponentController(props: Props): ViewProps {
  const [tasks, setTasks] = useState(props.tasks);

  // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate');

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged');

  // Sync stream updates to local tasks
  useEffect(() => {
    if (taskChanged.latest) {
      const { action, task } = taskChanged.latest;
      if (action === 'create' && task) {
        setTasks((prev) => [...prev, task]);
      } else if (action === 'move' && task && task.id) {
        setTasks((prev) => prev.map((t) => (t.id === task.id ? { ...t, column: task.column } : t)));
      } else if (action === 'edit' && task && task.id) {
        setTasks((prev) => prev.map((t) => (t.id === task.id ? { ...t, title: task.title, priority: task.priority } : t)));
      } else if (action === 'delete' && task && task.id) {
        setTasks((prev) => prev.filter((t) => t.id !== task.id));
      }
    }
  }, [taskChanged.latest]);

  // Compute totals
  const totalTasks = tasks.length;
  const completedTasks = tasks.filter((t) => t.column === props.columns.find((c) => c.name === 'Done')?.id).length;

  // Handlers
  const handleMoveTask = useCallback((taskId: string, newColumn: string) => {
    setTasks((prev) => prev.map((t) => (t.id === taskId ? { ...t, column: newColumn } : t)));
    taskUpdate({ action: 'move', taskId, data: { column: newColumn } });
  }, [taskUpdate]);

  const handleEditTask = useCallback((taskId: string, title: string) => {
    setTasks((prev) => prev.map((t) => (t.id === taskId ? { ...t, title } : t)));
    taskUpdate({ action: 'edit', taskId, data: { column: '' } });
  }, [taskUpdate]);

  const handleCreateTask = useCallback((title: string, priority: 'low' | 'medium' | 'high', columnId: string) => {
    const newId = `task-${Date.now()}`;
    const newTask = { id: newId, title, priority, column: columnId, assignee: '', dueDate: '' };
    setTasks((prev) => [...prev, newTask]);
    taskUpdate({ action: 'create', taskId: newId, data: { column: columnId } });
  }, [taskUpdate]);

  return {
    tasks,
    columns: props.columns,
    totalTasks,
    completedTasks,
    onMoveTask: handleMoveTask,
    onEditTask: handleEditTask,
    onCreateTask: handleCreateTask,
    taskChanges: taskChanged.latest,
  };
}

// View: presentation and UI interactions (can have its own UI state like tabs, modals, hover)
function ComponentView(props: ViewProps) {
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editTitle, setEditTitle] = useState('');
  const [addingColumnId, setAddingColumnId] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  const getPriorityColor = (priority?: string) => {
    switch (priority) {
      case 'high':
        return 'var(--ggui-color-error-600, #dc2626)';
      case 'medium':
        return 'var(--ggui-color-warning-600, #d97706)';
      case 'low':
      default:
        return 'var(--ggui-color-success-600, #16a34a)';
    }
  };

  const getPriorityVariant = (priority?: string) => {
    switch (priority) {
      case 'high':
        return 'error' as const;
      case 'medium':
        return 'warning' as const;
      case 'low':
      default:
        return 'success' as const;
    }
  };

  const handleStartEdit = (taskId: string, currentTitle: string) => {
