      props.onEditTask(taskId, editTitle);
    }
    setEditingTaskId(null);
  };

  const handleAddTask = () => {
    if (newTaskTitle.trim() && addingColumnId) {
      props.onCreateTask(newTaskTitle, newTaskPriority, addingColumnId);
      setNewTaskTitle('');
      setNewTaskPriority('medium');
      setAddingColumnId(null);
    }
  };

  return (
