        </Stack>

        {/* BOARD */}
        <Row gap={16} align="start" wrap={true}>
          {props.columns.map((column) => {
            const columnTasks = props.tasks.filter((t) => t.column === column.id);
            const isAdding = addingColumnId === column.id;

            return (
              <Box
                key={column.id}
                background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                borderRadius="var(--ggui-shape-radius-md, 8px)"
                padding={12}
                style={{ flex: '1 1 300px', minWidth: '300px', maxWidth: '400px' }}
              >
                <Stack gap={12} style={{ height: '100%' }}>
                  {/* COLUMN HEADER */}
                  <Stack direction="horizontal" justify="between" align="center">
                    <Stack direction="horizontal" gap={8} align="center">
                      <Heading level={4}>{column.name}</Heading>
                      <Badge variant="default" size="sm">{columnTasks.length}</Badge>
                    </Stack>
                  </Stack>

                  {/* TASK CARDS */}
                  <Stack gap={8}>
                    {columnTasks.map((task) => (
                      <Card
                        key={task.id}
                        padding={12}
                        shadow="sm"
                        radius="md"
                        border={true}
                        as={Hoverable}
                        hoverStyle={{ opacity: 0.95, boxShadow: 'var(--ggui-shape-shadow-md, 0 4px 6px -1px rgba(0,0,0,0.1))' }}
                      >
                        <Stack gap={8}>
                          {/* TASK TITLE (EDITABLE) */}
                          {editingTaskId === task.id ? (
                            <Stack direction="horizontal" gap={8}>
                              <Input
                                label="Task Title"
                                value={editTitle}
                                onChange={setEditTitle}
                                placeholder="Enter task title"
                                size="sm"
                              />
                              <Button
                                variant="primary"
                                size="sm"
                                onClick={() => handleSaveEdit(task.id || '')}
                              >
                                Save
                              </Button>
                              <Button
                                variant="ghost"
                                size="sm"
                                onClick={() => setEditingTaskId(null)}
                              >
                                Cancel
                              </Button>
                            ) : (
                              <Stack direction="horizontal" justify="between" align="center">
                                <Text
                                  as={Clickable}
                                  onClick={() => handleStartEdit(task.id || '', task.title || '')}
                                  variant="body"
                                  color="var(--ggui-color-onSurface, #18181b)"
                                  weight="medium"
                                  truncate
                                  is="span"
                                >
                                  {task.title}
                                </Text>
                                <Icon name="edit" size={14} color="var(--ggui-color-onSurfaceVariant, #52525b)" />
                              </Stack>
                            )}
                          {/* PRIORITY BADGE */}
                          {task.priority && (
                            <Badge variant={getPriorityVariant(task.priority)} size="sm" pill={true}>
                              {task.priority}
                            </Badge>
                          )}

                          {/* ASSIGNEE & DUE DATE */}
                          <Stack direction="horizontal" justify="between" align="center">
                            {task.assignee ? (
                              <Avatar name={task.assignee} size={24} shape="circle" />
                            ) : (
                              <Box style={{ width: '24px', height: '24px' }} />
                            )}
                            {task.dueDate && (
                              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                                {new Date(task.dueDate).toLocaleDateString()}
                              </Text>
                            )}
                          </Stack>

                          {/* MOVE CONTROLS */}
                          <Stack direction="horizontal" gap={6}>
                            {props.columns.map((otherCol) =>
                              otherCol.id !== column.id ? (
                                <Button
                                  key={`move-${task.id}-${otherCol.id}`}
                                  variant="ghost"
                                  size="xs"
                                  onClick={() => props.onMoveTask(task.id || '', otherCol.id || '')}
                                  style={{ fontSize: 'var(--ggui-font-size-xs, 12px)' }}
                                >
                                  → {otherCol.name}
                                </Button>
                              ) : null,
                            )}
                          </Stack>
                        </Stack>
                      </Card>
                    ))}
                  </Stack>

                  {/* ADD TASK BUTTON / FORM */}
                  {isAdding ? (
                    <Card padding={12} shadow="sm" radius="md" border={true} background="var(--ggui-color-surface, #ffffff)">
                      <Stack gap={8}>
                        <Input
                          label="New Task Title"
                          value={newTaskTitle}
                          onChange={setNewTaskTitle}
                          placeholder="Enter task title"
                          size="sm"
                        />
                        <Select
                          label="Priority"
                          value={newTaskPriority}
                          onChange={(val) => setNewTaskPriority(val as 'low' | 'medium' | 'high')}
                          options={[
                            { value: 'low', label: 'Low' },
                            { value: 'medium', label: 'Medium' },
                            { value: 'high', label: 'High' },
                          ]}
                          size="sm"
                        />
                        <Stack direction="horizontal" gap={8}>
                          <Button variant="primary" size="sm" onClick={handleAddTask} fullWidth>
                            Create
                          </Button>
                          <Button variant="ghost" size="sm" onClick={() => setAddingColumnId(null)} fullWidth>
                            Cancel
                          </Button>
                        </Stack>
                      </Stack>
                    </Card>
                  ) : (
                    <Button
                      variant="secondary"
                      size="sm"
                      onClick={() => setAddingColumnId(column.id || '')}
