/** Action payload: Called when user clicks Add to Cart. Payload: { productId, quantity } */
type ActionAddToCartPayload = { productId: string; quantity: number };





// ViewProps: define the props that ComponentView needs to render the UI.
// Include all data, callbacks, and computed values that the View will use.
interface ViewProps {
  product: Props['product'];
  quantity: number;
  onQuantityChange: (qty: number) => void;
  onAddToCart: () => void;
  activeTab: string;
  onTabChange: (key: string) => void;
}

// Controller: business logic, wire hooks, data transformations
function ComponentController(props: Props): ViewProps {
  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');

  // Actions — fire-and-forget to agent
  const addToCart = useAction<ActionAddToCartPayload>('addToCart'); // Called when user clicks Add to Cart. Payload: { productId, quantity }

  const handleAddToCart = useCallback(() => {
    if (props.product.id) {
      addToCart({ productId: props.product.id, quantity });
    }
  }, [props.product.id, quantity, addToCart]);

  const handleQuantityChange = useCallback((newQty: number) => {
    const maxStock = props.product.stock || 0;
    const clamped = Math.max(1, Math.min(newQty, maxStock));
    setQuantity(clamped);
  }, [props.product.stock]);

  return {
    product: props.product,
    quantity,
    onQuantityChange: handleQuantityChange,
    onAddToCart: handleAddToCart,
    activeTab,
    onTabChange: setActiveTab,
  };
}

// View: presentation and UI interactions (can have its own UI state like tabs, modals, hover)
function ComponentView(props: ViewProps) {
  // Helper: format currency using Intl.NumberFormat for locale-aware formatting
  const formatPrice = (price: number | undefined, currency: string | undefined) => {
    if (price === undefined) return 'N/A';
    const currencyCode = currency || 'USD';
    try {
      return new Intl.NumberFormat('en-US', {
        style: 'currency',
        currency: currencyCode,
      }).format(price);
    } catch {
      return `${currencyCode} ${price.toFixed(2)}`;
    }
  };

  // Helper: render star rating
  const renderStars = (rating: number | undefined) => {
    if (rating === undefined) return null;
    const stars = Array.from({ length: 5 }, (_, i) => i < Math.round(rating) ? '★' : '☆');
    return <Text variant="body">{stars.join('')}</Text>;
  };

  // Helper: determine stock badge
  const stockBadgeVariant = (stock: number | undefined) => {
    if (stock === undefined || stock === 0) return 'error';
    if (stock <= 5) return 'warning';
    return 'success';
  };

  const stockLabel = (stock: number | undefined) => {
    if (stock === undefined || stock === 0) return 'Out of Stock';
    if (stock <= 5) return 'Low Stock';
    return 'In Stock';
  };

  const isOutOfStock = (stock: number | undefined) => !stock || stock === 0;

  // Panel: Description
  const DescriptionPanel = () => (
    <Stack gap={12}>
      <Text variant="body">{props.product.description || 'No description available.'}</Text>
    </Stack>
  );

  // Panel: Specifications
  const SpecificationsPanel = () => {
    const specs = props.product.specifications as { key?: string; value?: string }[] | undefined;
    if (!specs || specs.length === 0) {
      return <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">No specifications available.</Text>;
    }
    return (
      <Table
        columns={[
          { key: 'key', header: 'Property', sortable: false },
          { key: 'value', header: 'Value', sortable: false },
        ]}
        data={specs}
        compact
      />
    );
  };

  // Panel: Reviews
  const ReviewsPanel = () => {
    const reviews = props.product.reviews as { author?: string; rating?: number; text?: string; date?: string }[] | undefined;
    if (!reviews || reviews.length === 0) {
      return <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">No reviews yet.</Text>;
    }
    return (
      <Stack gap={16}>
        {reviews.map((review, idx) => (
          <Card key={idx} shadow="sm" padding={16} border>
            <Stack gap={8}>
              <Stack direction="horizontal" gap={12} align="center" justify="between">
                <Text variant="label">{review.author || 'Anonymous'}</Text>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">{review.date || 'No date'}</Text>
              </Stack>
              <Text variant="bodySmall">{Array.from({ length: 5 }, (_, i) => i < (review.rating || 0) ? '★' : '☆').join('')}</Text>
              <Text variant="body">{review.text || 'No text provided.'}</Text>
            </Stack>
          </Card>
        ))}
      </Stack>
    );
  };

  return (
    <Container maxWidth="xl" padding={24}>
      <Stack gap={24}>
        {/* TOP SECTION: IMAGE + DETAILS */}
        <Stack direction="horizontal" gap={24} align="start" wrap>
          {/* Product Image Placeholder */}
          <Box
            background="var(--ggui-color-primary-50, #f0f9ff)"
            borderRadius={12}
            padding={32}
            style={{ minWidth: '300px', minHeight: '300px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}
          >
            <Stack align="center" gap={8}>
              <Icon name="image" size={48} color="var(--ggui-color-primary-300, #7dd3fc)" />
              <Text variant="bodySmall" color="var(--ggui-color-primary-600, #0284c7)">{props.product.name || 'Product'}</Text>
            </Stack>
          </Box>

          {/* Details Column */}
          <Stack gap={16} style={{ flex: 1, minWidth: '300px' }}>
            {/* Title */}
            <Heading level={2}>{props.product.name || 'Product'}</Heading>

            {/* Price & Rating Row */}
            <Stack direction="horizontal" gap={16} align="center">
              <Heading level={3} color="var(--ggui-color-primary-600, #0284c7)">{formatPrice(props.product.price, props.product.currency)}</Heading>
              <Stack direction="horizontal" gap={8} align="center">
                {renderStars(props.product.rating)}
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">({props.product.reviewCount || 0})</Text>
              </Stack>
            </Stack>

            {/* Stock Badge */}
            <Badge variant={stockBadgeVariant(props.product.stock) as any}>{stockLabel(props.product.stock)}</Badge>
          </Stack>
        </Stack>

        {/* MIDDLE SECTION: TAB NAVIGATION */}
        <Tabs
          items={[
            { key: 'description', label: 'Description', content: <DescriptionPanel /> },
            { key: 'specifications', label: 'Specifications', content: <SpecificationsPanel /> },
            { key: 'reviews', label: 'Reviews', content: <ReviewsPanel /> },
          ]}
          activeKey={props.activeTab}
          onChange={props.onTabChange}
          variant="line"
        />

        {/* BOTTOM SECTION: QUANTITY + ADD TO CART */}
        <Stack direction="horizontal" gap={16} align="center">
          {/* Quantity Selector */}
          <Stack direction="horizontal" gap={8} align="center">
            <Text variant="label">Quantity:</Text>
            <Stack direction="horizontal" gap={8} align="center" style={{ border: '1px solid var(--ggui-color-outline, #d4d4d8)', borderRadius: 'var(--ggui-shape-radius-md, 8px)', padding: '4px' }}>
              <Button
                size="sm"
                variant="ghost"
                onClick={() => props.onQuantityChange(props.quantity - 1)}
                disabled={props.quantity <= 1}
              >
                −
              </Button>
              <Text variant="body" style={{ minWidth: '30px', textAlign: 'center' }}>{props.quantity}</Text>
              <Button
                size="sm"
                variant="ghost"
                onClick={() => props.onQuantityChange(props.quantity + 1)}
                disabled={props.quantity >= (props.product.stock || 0)}
              >
                +
              </Button>
            </Stack>
          </Stack>

          {/* Add to Cart Button */}
          <Button
            variant="primary"
            size="lg"
            onClick={props.onAddToCart}
            disabled={isOutOfStock(props.product.stock)}
          >
            Add to Cart
          </Button>
        </Stack>
      </Stack>
    </Container>
  );
}

