  inputValue: string;
  onInputChange: (value: string) => void;
  onSendMessage: () => void;
}

// Controller: business logic, wire hooks, data transformations
function ComponentController(props: Props): ViewProps {
  const [inputValue, setInputValue] = useState('');
  const [allMessages, setAllMessages] = useState(props.messages);
  const [typingUser, setTypingUser] = useState<string | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  // Update messages from stream
  useEffect(() => {
    if (message.latest) {
      setAllMessages(prev => [...prev, message.latest!]);
    }
  }, [message.latest]);

  // Update typing indicator from stream
  useEffect(() => {
    if (typing.latest) {
      if (typing.latest.active) {
        setTypingUser(typing.latest.sender || null);
      } else {
        setTypingUser(null);
      }
    }
  }, [typing.latest]);

  // Auto-scroll to bottom when messages change
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [allMessages, typingUser]);

  const handleSendMessage = useCallback(() => {
    if (inputValue.trim()) {
      sendMessage({
        text: inputValue,
        timestamp: new Date().toISOString(),
      });
      setInputValue('');
    }
  }, [inputValue, sendMessage]);

  const handleInputChange = useCallback((value: string) => {
    setInputValue(value);
  }, []);

  return {
    title: props.title,
    participantCount: props.participantCount,
    messages: props.messages,
    currentUser: props.currentUser,
    allMessages,
    typingUser,
    inputValue,
    onInputChange: handleInputChange,
    onSendMessage: handleSendMessage,
  };
}
}

