              })}

              {/* TYPING INDICATOR */}
              {props.typingUser && (
                <Box style={{ display: 'flex', justifyContent: 'flex-start' }}>
                  <Stack direction="horizontal" gap={4} align="center">
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
