// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useStream } from '@ggui-ai/wire';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>; // Array of stocks with symbol, name, price, change, changePercent
}
// DO NOT EDIT types below — auto-generated from the data contract


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };




// ViewProps: define the props that ComponentView needs to render the UI.
// Include all data, callbacks, and computed values that the View will use.
interface ViewProps {
  stocks: Array<{ symbol: string; name: string; price: number; change: number; changePercent: number; isUpdating?: boolean }>;
  lastUpdated: string;
}
// Controller: business logic, wire hooks, data transformations
function ComponentController(props: Props): ViewProps {
  const [stocks, setStocks] = useState<Array<{ symbol: string; name: string; price: number; change: number; changePercent: number; isUpdating?: boolean }>>(props.stocks.map(s => ({ ...s, symbol: s.symbol || '', name: s.name || '', price: s.price || 0, change: s.change || 0, changePercent: s.changePercent || 0 })));
  const [lastUpdated, setLastUpdated] = useState(new Date().toLocaleTimeString());
  const updatingRef = useRef<Set<string>>(new Set());

  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate');
  const marketStatus = useStream<StreamMarketStatus>('marketStatus');

  useEffect(() => {
    if (priceUpdate.latest && priceUpdate.latest.symbol) {
      const update = priceUpdate.latest;
      setStocks(prev => prev.map(stock => {
        if (stock.symbol === update.symbol) {
          updatingRef.current.add(update.symbol);
          setTimeout(() => updatingRef.current.delete(update.symbol!), 600);
          return {
            ...stock,
            price: update.price ?? stock.price,
            change: update.change ?? stock.change,
            changePercent: update.changePercent ?? stock.changePercent,
            isUpdating: true
          };
        }
        return stock;
      }));
      setLastUpdated(new Date().toLocaleTimeString());
    }
  }, [priceUpdate.latest, marketStatus.latest]);

  return {
    stocks: stocks.map(s => ({ ...s, isUpdating: updatingRef.current.has(s.symbol) })),
    lastUpdated
  };
}
// Stock card sub-component with flash animation
function StockCard({ stock, isFlashing }: { stock: typeof ViewProps.prototype.stocks[0]; isFlashing?: boolean }): JSX.Element {
  const changeColor = stock.change >= 0 ? 'var(--ggui-color-success-600, #16a34a)' : 'var(--ggui-color-error-600, #dc2626)';
  const changeBorderColor = stock.change >= 0 ? 'var(--ggui-color-success-200, #bbf7d0)' : 'var(--ggui-color-error-200, #fecaca)';
  const arrowIcon = stock.change >= 0 ? '▲' : '▼';

  return (
    <Card
      padding={16}
      border={true}
      shadow="sm"
      radius="md"
      style={{
        borderColor: stock.isUpdating ? changeBorderColor : 'var(--ggui-color-outline, #d4d4d8)',
        borderColor: isFlashing ? changeBorderColor : 'var(--ggui-color-outline, #d4d4d8)',
        animation: isFlashing ? 'ggui-flash 600ms ease-out 1' : 'none',
        transition: 'border-color 200ms ease-in-out'
      }}
    >
      <Stack gap={8}>
        <Heading level={4} color="var(--ggui-color-onSurface, #18181b)">{stock.symbol}</Heading>
        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">{stock.name}</Text>
        <Divider margin={8} />
        <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">
          ${stock.price.toFixed(2)}
        </Text>
        <Stack direction="horizontal" gap={8} align="center">
          <Text variant="label" color={changeColor}>
            {arrowIcon} {Math.abs(stock.change).toFixed(2)}
          </Text>
          <Badge
            variant={stock.change >= 0 ? 'success' : 'error'}
            size="sm"
          >
            {stock.changePercent >= 0 ? '+' : ''}{stock.changePercent.toFixed(2)}%
          </Badge>
        </Stack>
      </Stack>
    </Card>
  );
}

// View: presentation and UI interactions
function ComponentView(props: ViewProps): JSX.Element {
  return (
      <style>{`
        @keyframes ggui-flash {
          0% { background-color: var(--ggui-color-primary-100, #e0f2fe); }
          100% { background-color: var(--ggui-color-surface, #fafafa); }
        }
        @media (max-width: 768px) {
          .stock-grid {
            grid-template-columns: repeat(1, 1fr) !important;
          }
        }
        @media (min-width: 769px) and (max-width: 1024px) {
          .stock-grid {
            grid-template-columns: repeat(2, 1fr) !important;
          }
        }
      `}</style>
      <style>{`
        @keyframes ggui-flash {
          0% { background-color: var(--ggui-color-primary-100, #e0f2fe); }
          100% { background-color: var(--ggui-color-surface, #fafafa); }
        }
      `}</style>
      <Stack gap={16}>
        {/* HEADER */}
        <Stack gap={8} direction="horizontal" justify="between" align="center">
          <Heading level={2}>Market Watch</Heading>
          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Last Updated: {props.lastUpdated}
          </Text>
        </Stack>

        {/* RESPONSIVE STOCK GRID: 3 cols desktop, 1 col mobile */}
        <Box
          className="stock-grid"
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(3, 1fr)',
            gap: 'var(--ggui-spacing-4, 16px)',
          } as React.CSSProperties}
        >
        >
          {props.stocks.map(stock => (
            <StockCard key={stock.symbol} stock={stock} isFlashing={stock.isUpdating} />
          ))}
        </Box>
      </Stack>
    </Container>
  );
}

// DO NOT EDIT render — it connects Controller to View
export default function render(props: Props) {
  const viewProps = ComponentController(props);
  return <ComponentView {...viewProps} />;
}

