import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// import { ... } from '@ggui-ai/adapters'; // TODO: adapter integration
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}
// DO NOT EDIT types below — auto-generated from the data contract

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };





// ViewProps: define the props that ComponentView needs to render the UI.
// Include all data, callbacks, and computed values that the View will use.
interface ViewProps {
  currentStep: 1 | 2 | 3;
  formData: {
    name: string;
    email: string;
    avatar: string;
    role: string;
    emailNotifications: boolean;
    theme: 'light' | 'dark';
  };
  errors: {
    name?: string;
    email?: string;
  };
  onFormChange: (field: string, value: unknown) => void;
  onNextStep: () => void;
  onPreviousStep: () => void;
  onComplete: () => void;
  avatarOptions: string[];
  roleOptions: string[];
  isNextDisabled: boolean;
}

// Controller: business logic, wire hooks, data transformations
function ComponentController(props: Props): ViewProps {
  const [currentStep, setCurrentStep] = useState<1 | 2 | 3>(1);
  const [formData, setFormData] = useState({
    name: props.initialProfile.name || '',
    email: props.initialProfile.email || '',
    avatar: props.initialProfile.avatar || props.avatarOptions[0] || '👤',
    role: props.initialProfile.role || props.roleOptions[0] || '',
    emailNotifications: props.initialProfile.emailNotifications ?? true,
    theme: (props.initialProfile.theme as 'light' | 'dark') || 'light',
  });
  const [errors, setErrors] = useState<{ name?: string; email?: string }>({});

  const complete = useAction<ActionCompletePayload>('complete');

  const validateEmail = (email: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(email);
  };

  const validateStep1 = (): boolean => {
    const newErrors: { name?: string; email?: string } = {};
    if (!formData.name.trim()) {
      newErrors.name = 'Name is required';
    }
    if (!formData.email.trim()) {
      newErrors.email = 'Email is required';
    } else if (!validateEmail(formData.email)) {
      newErrors.email = 'Please enter a valid email address';
    }
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const onFormChange = useCallback((field: string, value: unknown) => {
    setFormData((prev) => ({ ...prev, [field]: value }));
    setErrors((prev) => ({ ...prev, [field]: undefined }));
  }, []);

  const onNextStep = useCallback(() => {
    if (currentStep === 1 && !validateStep1()) {
      return;
    }
    setCurrentStep((prev) => Math.min(3, prev + 1) as 1 | 2 | 3);
  }, [currentStep, formData]);

  const onPreviousStep = useCallback(() => {
    setCurrentStep((prev) => Math.max(1, prev - 1) as 1 | 2 | 3);
  }, []);

  const onComplete = useCallback(() => {
    complete({
      name: formData.name,
      email: formData.email,
      avatar: formData.avatar,
      role: formData.role,
      emailNotifications: formData.emailNotifications,
      theme: formData.theme,
    });
  }, [formData, complete]);

  const isNextDisabled = useMemo(() => {
    if (currentStep === 1) {
      return !formData.name.trim() || !formData.email.trim() || !validateEmail(formData.email);
    }
    return false;
  }, [currentStep, formData]);

  return {
    currentStep,
    formData,
    errors,
    onFormChange,
    onNextStep,
    onPreviousStep,
    onComplete,
    avatarOptions: props.avatarOptions,
    roleOptions: props.roleOptions,
    isNextDisabled,
  };
}

// View: presentation and UI interactions (can have its own UI state like tabs, modals, hover)
function ComponentView(props: ViewProps) {
  const progressPercentage = ((props.currentStep - 1) / 2) * 100;

  return (
    <Container maxWidth="xl" padding={24}>
      <Stack gap={24}>
        {/* STEP INDICATOR */}
        <Stack gap={8}>
          <Stack direction="horizontal" justify="between" align="center">
            <Heading level={2}>Setup Your Profile</Heading>
            <Text variant="label">Step {props.currentStep} of 3</Text>
          </Stack>
          <Progress value={progressPercentage} max={100} size="md" variant="default" />
        </Stack>

        {/* STEP 1: PROFILE SETUP */}
        {props.currentStep === 1 && (
          <Card padding={24} shadow="md">
            <Stack gap={16}>
              <Heading level={3}>Profile Setup</Heading>
              <Stack gap={12}>
                <Input
                  label="Name"
                  placeholder="Enter your name"
                  value={props.formData.name}
                  onChange={(value) => props.onFormChange('name', value)}
                  error={props.errors.name}
                  required
                />
                <Input
                  label="Email"
                  type="email"
                  placeholder="Enter your email"
                  value={props.formData.email}
                  onChange={(value) => props.onFormChange('email', value)}
                  error={props.errors.email}
                  required
                />
                <Stack gap={8}>
                  <Text variant="label">Avatar</Text>
                  <Stack direction="horizontal" gap={12} wrap>
                    {props.avatarOptions.map((avatar) => (
                      <Card
                        key={avatar}
                        as={Clickable}
                        onClick={() => props.onFormChange('avatar', avatar)}
                        padding={12}
                        shadow={props.formData.avatar === avatar ? 'md' : 'sm'}
                        border={props.formData.avatar === avatar}
                        radius="lg"
                        style={{
                          cursor: 'pointer',
                          borderColor: props.formData.avatar === avatar ? 'var(--ggui-color-primary-600, #0284c7)' : undefined,
                          borderWidth: props.formData.avatar === avatar ? '2px' : undefined,
                        }}
                      >
                        <Text size="2xl">{avatar}</Text>
                      </Card>
                    ))}
                  </Stack>
                </Stack>
              </Stack>
            </Stack>
          </Card>
        )}

        {/* STEP 2: PREFERENCES */}
        {props.currentStep === 2 && (
          <Card padding={24} shadow="md">
            <Stack gap={16}>
              <Heading level={3}>Preferences</Heading>
              <Stack gap={12}>
                <Select
                  label="Role"
                  value={props.formData.role}
                  onChange={(value) => props.onFormChange('role', value)}
                  options={props.roleOptions.map((role) => ({
                    value: role,
                    label: role,
                  }))}
                  placeholder="Select your role"
                />
                <Stack gap={8}>
                  <Toggle
                    label="Email Notifications"
                    checked={props.formData.emailNotifications}
                    onChange={(checked) => props.onFormChange('emailNotifications', checked)}
                    size="md"
                  />
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    Receive email updates about your account activity
                  </Text>
                </Stack>
                <Stack gap={8}>
                  <Toggle
                    label={`Theme (${props.formData.theme === 'light' ? 'Light' : 'Dark'})`}
                    checked={props.formData.theme === 'dark'}
                    onChange={(checked) => props.onFormChange('theme', checked ? 'dark' : 'light')}
                    size="md"
                  />
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    Choose your preferred color theme
                  </Text>
                </Stack>
              </Stack>
            </Stack>
          </Card>
        )}

        {/* STEP 3: REVIEW */}
        {props.currentStep === 3 && (
          <Card padding={24} shadow="md">
            <Stack gap={16}>
              <Heading level={3}>Review & Confirm</Heading>
              <Stack gap={16}>
                <Box background="var(--ggui-color-primary-50, #f0f9ff)" padding={16} borderRadius={8}>
                  <Stack gap={12}>
                    <Stack direction="horizontal" gap={12} align="start">
                      <Stack gap={4} align="start">
                        <Text variant="label">Name</Text>
                        <Text>{props.formData.name}</Text>
                      </Stack>
                    </Stack>
                    <Divider margin={0} />
                    <Stack gap={4}>
                      <Text variant="label">Email</Text>
                      <Text>{props.formData.email}</Text>
                    </Stack>
                    <Divider margin={0} />
                    <Stack gap={4}>
                      <Text variant="label">Avatar</Text>
                      <Text size="2xl">{props.formData.avatar}</Text>
                    </Stack>
                    <Divider margin={0} />
                    <Stack gap={4}>
                      <Text variant="label">Role</Text>
                      <Text>{props.formData.role}</Text>
                    </Stack>
                    <Divider margin={0} />
                    <Stack gap={4}>
                      <Text variant="label">Email Notifications</Text>
                      <Badge variant={props.formData.emailNotifications ? 'success' : 'default'}>
                        {props.formData.emailNotifications ? 'Enabled' : 'Disabled'}
                      </Badge>
                    </Stack>
                    <Divider margin={0} />
                    <Stack gap={4}>
                      <Text variant="label">Theme</Text>
                      <Text>{props.formData.theme === 'light' ? '☀️ Light' : '🌙 Dark'}</Text>
                    </Stack>
                  </Stack>
                </Box>
              </Stack>
            </Stack>
          </Card>
        )}

        {/* NAVIGATION BUTTONS */}
        <Row gap={12} justify="between">
          <Button
            variant="ghost"
            onClick={props.onPreviousStep}
            disabled={props.currentStep === 1}
          >
            Go Back
          </Button>
          {props.currentStep < 3 && (
            <Button
              variant="primary"
              onClick={props.onNextStep}
              disabled={props.isNextDisabled}
            >
              Next
            </Button>
          )}
          {props.currentStep === 3 && (
            <Button variant="primary" onClick={props.onComplete}>
              Complete Setup
            </Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}

// DO NOT EDIT render — it connects Controller to View
export default function render(props: Props) {
  const viewProps = ComponentController(props);
  return <ComponentView {...viewProps} />;
}
